<?php
require_once dirname(__DIR__) . '/includes/functions.php';
websitePermissionGuard('website_compare');
$pdo=getDB();if(isset($_GET['add'])){try{ecom33AddCompareItem($pdo,(int)$_GET['add']);}catch(Throwable $e){}redirect('/store/compare.php');}
$cid=ecom33GetCompareSession($pdo);$items=$pdo->prepare('SELECT ci.*,p.name,p.sku,p.price,p.compare_price,p.stock,p.specifications,p.warranty,p.badge FROM '.table('product_comparison_items').' ci LEFT JOIN '.table('products').' p ON p.id=ci.product_id WHERE ci.product_comparison_session_id=? ORDER BY ci.sort_order,ci.created_at');$items->execute([$cid]);$items=$items->fetchAll();$products=$pdo->query('SELECT id,name,sku,price FROM '.table('products').' WHERE active=1 ORDER BY created_at DESC LIMIT 12')->fetchAll();
?><!doctype html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Compare Products</title><?php echo <<<'CSS'
<style>
body{margin:0;background:#f8fafc;color:#0f172a;font-family:Inter,Arial,sans-serif}.wrap{max-width:1180px;margin:auto;padding:24px}.hero{background:linear-gradient(135deg,#0f172a,#1e293b);color:#fff;border-radius:28px;padding:34px;margin-bottom:22px}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:16px}.card{background:#fff;border:1px solid #e2e8f0;border-radius:22px;padding:18px;box-shadow:0 12px 28px rgba(15,23,42,.06)}.btn{display:inline-block;border:0;border-radius:14px;background:#0f172a;color:#fff;padding:11px 14px;text-decoration:none;cursor:pointer}.btn2{background:#fff;color:#0f172a;border:1px solid #cbd5e1}.input{width:100%;box-sizing:border-box;border:1px solid #cbd5e1;border-radius:14px;padding:11px;margin-bottom:10px}.muted{color:#64748b}.price{font-size:22px;font-weight:800}.table{width:100%;border-collapse:collapse}.table td,.table th{padding:12px;border-bottom:1px solid #e2e8f0;text-align:left}@media(max-width:700px){.wrap{padding:14px}.hero{padding:24px}.grid{grid-template-columns:1fr}.table{font-size:13px}}</style>
CSS; ?></head><body><div class="wrap"><div class="hero"><h1>Product Comparison</h1><p>Compare price, stock, warranty and specifications before sending a quote request.</p></div><div class="grid"><?php foreach($items as $i): ?><div class="card"><h2><?php echo esc($i['name']); ?></h2><p class="muted"><?php echo esc($i['sku']); ?> · <?php echo esc($i['badge']); ?></p><div class="price"><?php echo money($i['price']); ?></div><p>Stock: <?php echo (int)$i['stock']; ?></p><p>Warranty: <?php echo esc($i['warranty']); ?></p><pre style="white-space:pre-wrap"><?php echo esc($i['specifications']); ?></pre></div><?php endforeach; ?></div><div class="card" style="margin-top:16px"><h2>Add to compare</h2><?php foreach($products as $p): ?><a class="btn btn2" style="margin:4px" href="?add=<?php echo (int)$p['id']; ?>"><?php echo esc($p['name']); ?></a><?php endforeach; ?></div></div></body></html>